import grpc
from concurrent import futures
import time
from typing import Iterator
import userservice_pb2
import userservice_pb2_grpc

# ── In-memory database ──────────────────────────────────
users_db = {
    "1": {"id": "1", "name": "John Doe", "email": "john@example.com", "role": "ADMIN"},
    "2": {"id": "2", "name": "Jane Smith", "email": "jane@example.com", "role": "USER"},
}
next_id = 3


# ── Service Implementation ──────────────────────────────
class UserServiceServicer(userservice_pb2_grpc.UserServiceServicer):
    def GetUser(self, request: userservice_pb2.GetUserRequest, context) -> userservice_pb2.User:
        user = users_db.get(request.id)
        if not user:
            context.abort(grpc.StatusCode.NOT_FOUND, f"User {request.id} not found")
        return userservice_pb2.User(**user)

    def ListUsers(self, request: userservice_pb2.ListUsersRequest, context) -> Iterator[userservice_pb2.User]:
        users = list(users_db.values())
        start = 0
        if request.page_token:
            start = next(
                (i for i, u in enumerate(users) if u["id"] == request.page_token),
                0
            )

        end = start + request.page_size if request.page_size else len(users)
        for user in users[start:end]:
            yield userservice_pb2.User(**user)

    def CreateUser(self, request: userservice_pb2.CreateUserRequest, context) -> userservice_pb2.User:
        global next_id
        user = {
            "id": str(next_id),
            "name": request.name,
            "email": request.email,
            "role": userservice_pb2.UserRole.Name(request.role)
        }
        users_db[str(next_id)] = user
        next_id += 1
        return userservice_pb2.User(**user)

    def StreamUsers(self, request, context) -> Iterator[userservice_pb2.User]:
        while True:
            for user in users_db.values():
                yield userservice_pb2.User(**user)
            time.sleep(5)

    def Chat(self, request_iterator: Iterator[userservice_pb2.ChatMessage], context) -> Iterator[userservice_pb2.ChatMessage]:
        for message in request_iterator:
            yield userservice_pb2.ChatMessage(
                user_id=message.user_id,
                content=f"Echo: {message.content}",
                timestamp=message.timestamp
            )


# ── Server Setup ────────────────────────────────────────
def serve():
    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=10),
        options=[
            ('grpc.max_receive_message_length', 50 * 1024 * 1024),
            ('grpc.max_send_message_length', 50 * 1024 * 1024),
        ]
    )

    userservice_pb2_grpc.add_UserServiceServicer_to_server(
        UserServiceServicer(), server
    )

    server.add_insecure_port('[::]:50051')
    server.start()
    print("gRPC server started on port 50051")

    try:
        while True:
            time.sleep(86400)
    except KeyboardInterrupt:
        server.stop(0)


if __name__ == '__main__':
    serve()
